const express = require('express');
const { me, updateProfile } = require('../controllers/profileController');
const { authenticate } = require('../middleware/authMiddleware');
const { updateProfileRules, handleValidationErrors } = require('../middleware/validators');

const router = express.Router();

router.get('/me', authenticate, me);
router.put('/profile', authenticate, updateProfileRules, handleValidationErrors, updateProfile);

module.exports = router;
